#    ~/.breakfast.toml
# =============================================================================


# -----------------------------------------------------------------------------
# Target
# Which organisation and repos to query by default.
# -----------------------------------------------------------------------------

# GitHub organisation to query for open pull requests.
# Equivalent to: breakfast -o <value>
